// PlayoffManager.js

export function generarPlayoffsParaLiga(liga, clasificacionCompleta) {
    const clasificacion = clasificacionCompleta[liga] || [];
    const nombreBase = liga.split(" - ")[0];
    let emparejamientos = [];

    const top5 = clasificacion.sort((a, b) => b.puntos - a.puntos).slice(1, 5); // del 2º al 5º

    if (nombreBase === "Liga 2") {
        emparejamientos = [
            [top5[0], top5[3]], // 2º vs 5º
            [top5[1], top5[2]]  // 3º vs 4º
        ];
    } else if (nombreBase === "Primera RFEF") {
        // Debemos cruzar grupos. Se recomienda recibir ambas clasificaciones como parámetro
        return generarPlayoffsPrimeraRFEF(clasificacionCompleta);
    } else if (nombreBase.includes("RFEF")) {
        emparejamientos = sortearPlayoffs(top5, clasificacion, nombreBase.includes("Tercera"));
    }

    return emparejamientos;
}
export function aplicarAscensosDescensos(playoffs, clasificacionPorLiga, equipos) {
    let nuevosEquipos = [...equipos];

    // Procesar descensos por liga
    for (let liga in clasificacionPorLiga) {
        const base = liga.split(" - ")[0];
        const descensos = clasificacionPorLiga[liga]
            .sort((a, b) => b.puntos - a.puntos)
            .slice(-3); // o -5 según config

        descensos.forEach(eq => {
            let equipo = nuevosEquipos.find(e => e.id === eq.id);
            if (equipo) equipo.liga = bajarDivision(equipo.liga, equipo.comunidad);
        });
    }

    // Procesar ganadores de playoffs
    playoffs.ganadores.forEach(id => {
        const equipo = nuevosEquipos.find(e => e.id === id);
        if (equipo) equipo.liga = subirDivision(equipo.liga, equipo.comunidad);
    });

    return nuevosEquipos;
}

function subirDivision(liga, comunidad) {
    if (liga.includes("Tercera")) return seleccionarGrupoSegundaRFEF(comunidad);
    if (liga.includes("Segunda")) return seleccionarGrupoPrimeraRFEF(comunidad);
    if (liga.includes("Primera")) return "Liga 2";
    if (liga === "Liga 2") return "La Liga";
}

function bajarDivision(liga, comunidad) {
    if (liga === "La Liga") return "Liga 2";
    if (liga === "Liga 2") return seleccionarGrupoPrimeraRFEF(comunidad);
    if (liga.includes("Primera")) return seleccionarGrupoSegundaRFEF(comunidad);
    if (liga.includes("Segunda")) return seleccionarGrupoTerceraRFEF(comunidad);
}

function seleccionarGrupoPrimeraRFEF(comunidad) {
    const norte = ["Galicia", "Asturias", "Cantabria", "País Vasco", "Navarra", "Castilla y León"];
    return norte.includes(comunidad) ? "Primera RFEF - Grupo 1" : "Primera RFEF - Grupo 2";
}

function seleccionarGrupoSegundaRFEF(comunidad) {
    // Similar, por cercanía
}

function seleccionarGrupoTerceraRFEF(comunidad) {
    return `Tercera RFEF - ${comunidad}`;
}
function sortearPlayoffs(top5, clasificacion, esTercera) {
    let emparejamientos = [];
    const [a, b, c, d] = mezclar([...top5]);
    emparejamientos.push([a, d]);
    emparejamientos.push([b, c]);

    if (esTercera) {
        // Esto devuelve una ronda, luego vendrá una segunda ronda
        return emparejamientos;
    } else {
        return emparejamientos; // segunda RFEF
    }
}

function generarPlayoffsPrimeraRFEF(clasificaciones) {
    const g1 = clasificaciones["Primera RFEF - Grupo 1"];
    const g2 = clasificaciones["Primera RFEF - Grupo 2"];
    const s = (lista, i) => lista.sort((a, b) => b.puntos - a.puntos)[i];

    return [
        [s(g1, 1), s(g2, 4)], // 2º G1 vs 5º G2
        [s(g2, 2), s(g1, 3)], // 3º G2 vs 4º G1
        [s(g2, 1), s(g1, 4)],
        [s(g1, 2), s(g2, 3)],
    ];
}

function mezclar(array) {
    for (let i = array.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [array[i], array[j]] = [array[j], array[i]];
    }
    return array;
}
